     5→// Minimal .env loader (no extra dependencies)
     6→if (file_exists(__DIR__ . '/../.env')) {
     7→    foreach (file(__DIR__ . '/../.env', FILE_IGNORE_NEW_LINES | FILE_SKIP_EMPTY_LINES) as $line) {
